def test_tracked_langsmith_reports_include_next_action_state_fields() -> None:
    for report_path in (
        Path("reports/langsmith-eval-sync.json"),
        Path("reports/langsmith-eval-sync-preflight.json"),
    ):
        report = json.loads(report_path.read_text(encoding="utf-8"))
        next_action_ids = [
            action["id"] for action in cast(list[dict[str, object]], report.get("nextActions", []))
        ]
        assert next_action_ids, f"{report_path} should preserve nextActions"
        state_ids = set(cast(dict[str, str], report.get("nextActionStates", {})))
        assert state_ids == set(next_action_ids)
        assert report.get("readyNextActionIds") or report.get("blockedNextActionIds")
        evidence = cast(dict[str, object], report.get("evidence", {}))
        assert evidence.get("nextActionStates") == report["nextActionStates"]
        assert evidence.get("readyNextActionIds") == report["readyNextActionIds"]
        assert evidence.get("blockedNextActionIds") == report["blockedNextActionIds"]


def test_release_readiness_binds_inputs_to_head_time_and_hash(tmp_path: Path) -> None:
    input_path = tmp_path / "gate.json"
    payload: dict[str, Any] = {
        "ok": True,
        "status": "passed",
        "scope": "test",
        "evidence": {},
    }
    input_path.write_text(json.dumps(payload), encoding="utf-8")
    now = datetime.now(UTC)

    report = build_release_readiness_report_from_payloads(
        [("test_gate", payload, str(input_path))],
        expected_commit=current_git_commit(),
        max_input_age_seconds=3600,
        generated_at=now,
    )

    provenance = cast(dict[str, object], report["provenance"])
    inputs = cast(list[dict[str, object]], provenance["inputs"])
    assert provenance["commitSha"] == current_git_commit()
    assert provenance["expectedCommitSha"] == current_git_commit()
    assert isinstance(provenance["generatedAt"], str)
    assert len(cast(str, provenance["inputHash"])) == 64
    assert len(cast(str, inputs[0]["inputHash"])) == 64
    assert report["ok"] is True


def test_release_readiness_fails_closed_for_stale_input(tmp_path: Path) -> None:
    input_path = tmp_path / "stale.json"
    payload: dict[str, Any] = {
        "ok": True,
        "status": "passed",
        "scope": "test",
        "evidence": {},
    }
    input_path.write_text(json.dumps(payload), encoding="utf-8")
    now = datetime.now(UTC)
    stale_time = (now - timedelta(hours=2)).timestamp()
    os.utime(input_path, (stale_time, stale_time))

    report = build_release_readiness_report_from_payloads(
        [("test_gate", payload, str(input_path))],
        expected_commit=current_git_commit(),
        max_input_age_seconds=60,
        generated_at=now,
    )

    assert report["ok"] is False
    item = cast(list[dict[str, object]], report["items"])[0]
    assert item["status"] == "failed"
    assert item["failure"] == "stale readiness input evidence"


def test_release_readiness_fails_closed_when_expected_commit_is_not_head() -> None:
    payload: dict[str, Any] = {
        "ok": True,
        "status": "passed",
        "scope": "test",
        "evidence": {},
    }

    report = build_release_readiness_report_from_payloads(
        [("test_gate", payload, "in-memory")],
        expected_commit="0" * 40,
        max_input_age_seconds=60,
    )

    assert report["ok"] is False
    item = cast(list[dict[str, object]], report["items"])[0]
    assert item["status"] == "failed"
    assert cast(str, item["failure"]).startswith("readiness HEAD mismatch")


