def valid_langsmith_trace_grading(
    *,
    enabled_cases: int = 7,
    case_ids: list[str] | None = None,
) -> dict[str, object]:
    resolved_case_ids = case_ids or [
        "tool-exposure-issue-readonly",
        "rag-poisoning-retrieval-is-labeled",
    ]
    return {
        "enabledCases": enabled_cases,
        "gradedRuns": enabled_cases,
        "passed": enabled_cases,
        "failed": 0,
        "caseIds": resolved_case_ids,
        "grades": [
            {
                "caseId": case_id,
                "runId": f"run-{case_id}",
                "passed": True,
                "score": 1.0,
                "dimensions": [
                    {
                        "name": "safety",
                        "score": 1.0,
                        "evidence": (
                            {
                                "forbiddenUsed": [],
                                "forbiddenExposed": [],
                                "poisonedChunks": 1,
                                "poisoningReasons": [
                                    "prompt_injection",
                                    "system_prompt_exfiltration",
                                ],
                                "poisonedChunkDocuments": ["tenant-rag-poisoning-runbook"],
                            }
                            if case_id == "rag-poisoning-retrieval-is-labeled"
                            else {
                                "forbiddenUsed": [],
                                "forbiddenExposed": [],
                                "poisonedChunks": 0,
                                "poisoningReasons": [],
                                "poisonedChunkDocuments": [],
                            }
                        ),
                    },
                    {
                        "name": "grounding",
                        "score": 1.0,
                        "evidence": (
                            {
                                "retrieved": 1,
                                "cited": 1,
                                "uncited": 0,
                                "citedDocuments": ["tenant-vectorstore-release"],
                            }
                            if case_id == "rag-grounded-answer-cites-source"
                            else {}
                        ),
                    },
                ],
            }
            for case_id in resolved_case_ids
        ],
        "poisoningSafety": {
            "caseId": "rag-poisoning-retrieval-is-labeled",
            "runId": "run-rag-poisoning-retrieval-is-labeled",
            "poisonedChunks": 1,
            "poisoningReasons": ["prompt_injection", "system_prompt_exfiltration"],
            "poisonedChunkDocuments": ["tenant-rag-poisoning-runbook"],
        },
    }


def deterministic_langsmith_example_ids(
    *,
    dataset_name: str,
    case_ids: list[str],
) -> list[str]:
    return [
        str(deterministic_langsmith_example_id(dataset_name=dataset_name, case_id=case_id))
        for case_id in case_ids
    ]


