def test_release_readiness_accepts_documents_ask_hardening_handoff_without_candidate_boundary(
    tmp_path: Path,
) -> None:
    evidence = valid_langsmith_eval_sync_evidence()
    langsmith_report = "reports/langsmith-eval-sync.json"
    readiness_reports = {
        "hardening_suite": "reports/hardening-suite.json",
        "langsmith_eval_sync": langsmith_report,
    }
    readiness_command = release_readiness_command_for_reports(
        required_reports=("hardening_suite", "langsmith_eval_sync"),
        report_files=readiness_reports,
    )
    readiness_report_arg = (
        "--readiness-report hardening_suite=reports/hardening-suite.json "
        "--readiness-report langsmith_eval_sync=reports/langsmith-eval-sync.json"
    )
    evidence["readinessCommand"] = readiness_command
    evidence["readinessReportArg"] = readiness_report_arg
    evidence["requiredReadinessReports"] = ["hardening_suite", "langsmith_eval_sync"]
    evidence["readinessReports"] = readiness_reports
    evidence["nextActions"] = [
        {
            "id": "sync-langsmith",
            "label": "Run the LangSmith eval sync without dry-run",
            "command": evidence["liveSyncCommand"],
            "preflightFile": "reports/release/release-smoke-preflight.local.json",
            "preflightEnvTemplate": "reports/release/release-smoke-preflight.local.env",
            "releaseReadinessFile": "reports/release-readiness.json",
            "readinessReportArg": readiness_report_arg,
            "requiredReadinessReports": ["hardening_suite", "langsmith_eval_sync"],
            "readinessReports": readiness_reports,
        },
        {
            "id": "generate-hardening-suite",
            "label": "Generate the hardening suite report required for minor boundary review",
            "command": "uv run reactor-hardening-suite --report-file reports/hardening-suite.json",
            "readinessReportArg": "--readiness-report hardening_suite=reports/hardening-suite.json",
            "requiredReadinessReports": ["hardening_suite", "langsmith_eval_sync"],
            "readinessReports": readiness_reports,
        },
        {
            "id": "refresh-release-readiness",
            "label": "Refresh release readiness with promoted LangSmith and hardening reports",
            "command": readiness_command,
            "remediationCommand": readiness_command,
            "latestTagCommand": "git describe --tags --abbrev=0",
            "recommendedTagSource": "release_readiness.tagRecommendation.recommendedTag",
            "readinessReportArg": readiness_report_arg,
            "requiredReadinessReports": ["hardening_suite", "langsmith_eval_sync"],
            "readinessReports": readiness_reports,
        },
    ]

    langsmith = write_report(
        tmp_path / "langsmith-eval-sync.json",
        {
            "ok": True,
            "status": "passed",
            "scope": "langsmith_eval_dataset_sync",
            "evidence": evidence,
        },
    )

    report = build_release_readiness_report([("langsmith_eval_sync", langsmith)])

    assert report["ok"] is False
    assert report["status"] == "blocked"
    assert report["missingReports"] == ["hardening_suite"]
    items = {item["name"]: item for item in cast(list[dict[str, object]], report["items"])}
    assert items["langsmith_eval_sync"]["status"] == "passed"
    assert "failure" not in items["langsmith_eval_sync"]
    assert items["hardening_suite"]["status"] == "skipped"
    assert items["hardening_suite"]["failure"] == "required report missing"


