def test_tracked_release_readiness_tag_rec_preserves_langsmith_preflight_handoff() -> None:
    report_path = Path("reports/release-readiness.json")
    report = cast(dict[str, object], json.loads(report_path.read_text(encoding="utf-8")))
    recommendation = cast(dict[str, object], report["tagRecommendation"])
    items = {
        item["name"]: item
        for item in cast(list[dict[str, object]], report["items"])
        if isinstance(item.get("name"), str)
    }

    assert (
        recommendation["nextAction"]
        == "review release readiness warnings, then verify clean worktree and choose the "
        "next minor version tag"
    )
    assert recommendation["recommendedVersionBump"] == "minor"
    assert recommendation["recommendedTag"] == "v1.2.0"
    assert recommendation["minorEligible"] is True
    assert recommendation["minorBoundaryReports"] == ["langsmith_eval_sync"]
    assert recommendation["passedReports"] == [
        "smoke_run",
        "release_evidence",
        "hardening_suite",
        "langsmith_eval_sync",
    ]
    assert recommendation["warningReports"] == ["hardening_suite"]
    summary = readiness_failure_summary(report)
    assert "recommendedTagPattern=v1.2.0" in summary

    langsmith = items["langsmith_eval_sync"]
    assert langsmith["minorBoundaryResolvedEvidence"] == ["rag_ingestion_lifecycle"]
    assert langsmith["minorBoundaryResolvedByReports"] == {
        "rag_ingestion_lifecycle": "hardening_suite"
    }
    assert langsmith["productBoundaryExpectedResolvedByReports"] == {
        "rag_ingestion_lifecycle": "hardening_suite"
    }
    next_actions = {
        action["id"]: action
        for action in cast(list[dict[str, object]], langsmith["nextActions"])
        if isinstance(action.get("id"), str)
    }
    refresh = next_actions["refresh-release-readiness"]
    assert refresh["releaseReadinessFile"] == "reports/release-readiness.json"


def test_tracked_release_readiness_preserves_canonical_langsmith_review_note() -> None:
    report_path = Path("reports/release-readiness.json")
    report = cast(dict[str, object], json.loads(report_path.read_text(encoding="utf-8")))
    items = {
        item["name"]: item
        for item in cast(list[dict[str, object]], report["items"])
        if isinstance(item.get("name"), str)
    }
    langsmith = items["langsmith_eval_sync"]
    feedback_review_queue = cast(dict[str, object], langsmith["feedbackReviewQueue"])
    product_boundary = cast(dict[str, object], langsmith["productCapabilityBoundary"])

    assert feedback_review_queue["reviewNote"] == RAG_CANDIDATE_FEEDBACK_BULK_REVIEW_NOTE
    assert "feedback_promotion.reviewed_feedback" in cast(list[str], product_boundary["evidence"])
    assert "feedback_promotion.reviewed_feedback" not in cast(
        list[str], product_boundary.get("missingEvidence", [])
    )
    assert f"--feedback-review-note {RAG_CANDIDATE_FEEDBACK_BULK_REVIEW_NOTE!r}" in cast(
        str, langsmith["syncCommand"]
    )


