def test_release_readiness_prefers_feedback_review_before_langsmith_sync(
    tmp_path: Path,
) -> None:
    langsmith = write_report(
        tmp_path / "langsmith-eval-sync-dry-run.json",
        {
            "ok": False,
            "status": "skipped",
            "scope": "langsmith_eval_dataset_sync",
            "dryRun": True,
            "releaseGate": {
                "status": "blocked",
                "blocksReleaseReadiness": True,
                "reason": "dry_run_only",
                "requiredReport": "langsmith_eval_sync",
                "remediation": [
                    "run_reactor_langsmith_eval_sync_without_dry_run",
                    "include_passed_langsmith_eval_sync_report_in_release_readiness",
                ],
            },
            "nextActions": [
                {
                    "id": "bulk-review-feedback-grounded_citation",
                    "label": (
                        "Close promoted RAG candidate feedback after LangSmith eval handoff "
                        "is reviewed"
                    ),
                    "command": (
                        "reactor-admin feedback-bulk-review --candidate-tag "
                        "rag-candidate:grounded_citation --source slack_button "
                        "--status done --tag promoted --tag langsmith --output table"
                    ),
                    "readinessReportArg": (
                        "--readiness-report hardening_suite=reports/hardening-suite.json "
                        "--readiness-report langsmith_eval_sync=reports/langsmith.json"
                    ),
                    "requiredReadinessReports": ["hardening_suite", "langsmith_eval_sync"],
                    "readinessReports": {
                        "hardening_suite": "reports/hardening-suite.json",
                        "langsmith_eval_sync": "reports/langsmith.json",
                    },
                },
                {
                    "id": "sync-langsmith",
                    "label": "Run the LangSmith eval sync without dry-run",
                    "command": (
                        "uv run reactor-langsmith-eval-sync "
                        "--suite-file evals/regression/rag-ingestion-candidate.json "
                        "--dataset-name reactor-rag-ingestion-candidate "
                        "--report-file reports/langsmith.json"
                    ),
                    "requiredEnvAnyOf": [
                        ["LANGSMITH_API_KEY", "REACTOR_OBSERVABILITY_LANGSMITH_API_KEY"]
                    ],
                    "missingEnvAnyOf": [
                        "LANGSMITH_API_KEY|REACTOR_OBSERVABILITY_LANGSMITH_API_KEY"
                    ],
                    "recommendedEnv": ["LANGSMITH_ENDPOINT"],
                },
            ],
        },
    )

    report = build_release_readiness_report([("langsmith_eval_sync", langsmith)])

    recommendation = cast(dict[str, object], report["tagRecommendation"])
    assert recommendation["nextActionId"] == "bulk-review-feedback-grounded_citation"
    next_action_command = cast(str, recommendation["nextActionCommand"])
    assert next_action_command.startswith("reactor-admin feedback-bulk-review")
    assert recommendation["readinessReportArg"] == (
        "--readiness-report hardening_suite=reports/hardening-suite.json "
        "--readiness-report langsmith_eval_sync=reports/langsmith.json"
    )
    assert recommendation["blockingEnvActionId"] == "sync-langsmith"
    assert recommendation["blockingMissingEnvAnyOf"] == [
        "LANGSMITH_API_KEY|REACTOR_OBSERVABILITY_LANGSMITH_API_KEY"
    ]
    assert recommendation["blockingRequiredEnvAnyOf"] == [
        ["LANGSMITH_API_KEY", "REACTOR_OBSERVABILITY_LANGSMITH_API_KEY"]
    ]
    assert recommendation["blockingRecommendedEnv"] == ["LANGSMITH_ENDPOINT"]


