    langsmith_evidence["liveSyncCommand"] = langsmith_evidence["syncCommand"]
    langsmith_evidence["productCapabilityBoundary"] = {
        "minorEligible": False,
        "capability": "rag_ingest_to_feedback_eval_langsmith_readiness",
        "evidence": [
            "rag_ingestion_candidate_feedback_queue",
            "langsmith_trace_grading",
            "release_readiness_command",
        ],
        "missingEvidence": ["rag_ingestion_lifecycle"],
    }
    langsmith_evidence["readinessCommand"] = release_readiness_command_for_reports(
        required_reports=("hardening_suite", "langsmith_eval_sync"),
        report_files=langsmith_evidence["readinessReports"],
    )
    langsmith_evidence["releaseReadinessCommand"] = langsmith_evidence["readinessCommand"]
    langsmith_evidence["readinessReportArg"] = (
        "--readiness-report hardening_suite=reports/hardening-suite.json "
        "--readiness-report langsmith_eval_sync=reports/langsmith-rag-candidate.json"
    )
    langsmith_evidence["nextActions"] = [
        {
            "id": "review-rag-candidate-grounded_citation",
            "label": "Review the RAG ingestion candidate behind the LangSmith report",
            "command": (
                "reactor-admin rag-candidates --status INGESTED "
                "--tag collection:rag-ingestion-candidate "
                "--tag rag-candidate:grounded_citation --limit 10 --output table"
            ),
            "candidateTag": "rag-candidate:grounded_citation",
            "evalCaseId": "case_rag_candidate_grounded_citation",
            "sourceRunId": "run_rag_candidate_grounded_citation",
        },
        {
            "id": "sync-langsmith",
            "label": "Run the LangSmith eval sync without dry-run",
            "command": langsmith_evidence["liveSyncCommand"],
            "preflightFile": "reports/release/release-smoke-preflight.local.json",
            "preflightEnvTemplate": "reports/release/release-smoke-preflight.local.env",
            "releaseReadinessFile": "reports/release-readiness.json",
            "readinessReportArg": langsmith_evidence["readinessReportArg"],
            "requiredReadinessReports": ["hardening_suite", "langsmith_eval_sync"],
            "readinessReports": langsmith_evidence["readinessReports"],
        },
        {
            "id": "generate-hardening-suite",
            "label": "Generate the hardening suite report required for minor boundary review",
            "command": "uv run reactor-hardening-suite --report-file reports/hardening-suite.json",
            "readinessReportArg": "--readiness-report hardening_suite=reports/hardening-suite.json",
            "requiredReadinessReports": ["hardening_suite", "langsmith_eval_sync"],
            "readinessReports": langsmith_evidence["readinessReports"],
        },
        {
            "id": "refresh-release-readiness",
            "label": "Refresh release readiness with candidate LangSmith and hardening reports",
            "command": langsmith_evidence["readinessCommand"],
            "remediationCommand": langsmith_evidence["readinessCommand"],
            "latestTagCommand": "git describe --tags --abbrev=0",
            "recommendedTagSource": "release_readiness.tagRecommendation.recommendedTag",
            "recommendedVersionBump": "minor",
            "recommendedTagPattern": "v1.2.0",
            "minorBoundaryReports": ["langsmith_eval_sync"],
            "readinessReportArg": langsmith_evidence["readinessReportArg"],
            "requiredReadinessReports": ["hardening_suite", "langsmith_eval_sync"],
            "readinessReports": langsmith_evidence["readinessReports"],
        },
    ]
    langsmith = write_report(
        tmp_path / "langsmith-eval-sync.json",
        {
            "ok": True,
            "status": "passed",
            "scope": "langsmith_eval_dataset_sync",
            "evidence": langsmith_evidence,
        },
    )

    report = build_release_readiness_report([("langsmith_eval_sync", langsmith)])

    assert report["ok"] is False
    assert report["status"] == "blocked"
    assert report["requiredReports"] == ["hardening_suite", "langsmith_eval_sync"]
    assert report["missingReports"] == ["hardening_suite"]
    assert report["summary"] == {"total": 2, "passed": 1, "failed": 0, "skipped": 1}
    items = cast(list[dict[str, object]], report["items"])
    assert [item["name"] for item in items] == ["langsmith_eval_sync", "hardening_suite"]
    assert items[0]["releaseReadinessCommand"] == langsmith_evidence["readinessCommand"]
    assert items[1] == {
        "name": "hardening_suite",
        "ok": False,
        "status": "skipped",
        "scope": "",
        "artifact": "",
        "owner": "",
        "mode": "",
        "failure": "required report missing",
        "remediationCommand": (
            "uv run reactor-hardening-suite --report-file reports/hardening-suite.json"
        ),
        "readinessReportArg": ("--readiness-report hardening_suite=reports/hardening-suite.json"),
    }


