def test_release_readiness_report_blocks_when_required_report_is_missing(
    tmp_path: Path,
) -> None:
    hardening = write_report(
        tmp_path / "hardening-suite.json",
        {
            "ok": True,
            "status": "passed",
            "scope": "agent_release_gate",
            "evidence": {
                "artifact": "reports/hardening-suite.json",
                "owner": "reactor.evals",
                "mode": "local_agent_hardening_release_gate",
                "graphTopology": valid_graph_topology(),
                "contextManifest": valid_context_manifest(),
                "contextManifestDiagnostics": valid_context_manifest_diagnostics(),
                "langchainMiddlewarePolicy": valid_langchain_middleware_policy(),
                "langchainMiddlewareChain": valid_langchain_middleware_chain(),
                "langchainSerializationBoundary": valid_langchain_serialization_boundary(),
                "contextManagementLifecycle": valid_context_management_lifecycle(),
                "usageCostLifecycle": valid_usage_cost_lifecycle(),
                "checkpointProvenance": valid_checkpoint_provenance(),
                "structuredOutput": valid_structured_output(),
                "researchAnswerContract": valid_research_answer_contract(),
                "toolInvocationLifecycle": valid_tool_invocation_lifecycle(),
                "durableRunQueue": valid_durable_run_queue(),
                "outboxInboxLifecycle": valid_outbox_inbox_lifecycle(),
                "redisCoordination": valid_redis_coordination(),
                "mcpPreflight": valid_mcp_preflight(),
                "slackMcpSurfacePolicy": valid_slack_mcp_surface_policy(),
                "memoryMaintenanceLifecycle": valid_memory_maintenance_lifecycle(),
                "ragIngestionLifecycle": valid_rag_ingestion_lifecycle(),
                "artifactLifecycle": valid_artifact_lifecycle(),
                "promptReleaseLifecycle": valid_prompt_release_lifecycle(),
                "approvalLifecycle": valid_approval_lifecycle(),
                "providerFallbackPolicy": valid_provider_fallback_policy(),
                "langgraphFaultTolerance": valid_langgraph_fault_tolerance(),
                "checkpointRetentionPolicy": valid_checkpoint_retention_policy(),
                "streamingEventContract": valid_streaming_event_contract(),
            },
        },
    )

    report = build_release_readiness_report(
        [("hardening_suite", hardening)],
        required_reports=("observability_smoke", "hardening_suite"),
    )

    assert report["ok"] is False
    assert report["status"] == "blocked"
    assert report["requiredReports"] == ["observability_smoke", "hardening_suite"]
    assert report["missingReports"] == ["observability_smoke"]
    assert report["summary"] == {"total": 2, "passed": 1, "failed": 0, "skipped": 1}
    items = cast(list[dict[str, object]], report["items"])
    assert items[0]["name"] == "hardening_suite"
    assert items[1] == {
        "name": "observability_smoke",
        "ok": False,
        "status": "skipped",
        "scope": "",
        "artifact": "",
        "owner": "",
        "mode": "",
        "failure": "required report missing",
        "remediationCommand": (
            "uv run reactor-observability-smoke --output reports/observability-smoke.json"
        ),
        "readinessReportArg": (
            "--readiness-report observability_smoke=reports/observability-smoke.json"
        ),
    }
    assert report["tagRecommendation"] == {
        "status": "defer",
        "reason": "release readiness is blocked",
        "eligible": False,
        "recommendedVersionBump": "none",
        "recommendedTagPattern": "none",
        "minorEligible": False,
        "policy": "version tags are only for release-worthy batches or deployment candidates",
        "blockingReports": ["observability_smoke"],
        "passedReports": ["hardening_suite"],
        "nextAction": "resolve blocked/skipped release readiness reports before tagging",
        "remediationCommand": (
            "uv run reactor-observability-smoke --output reports/observability-smoke.json"
        ),
        "readinessReportArg": (
            "--readiness-report observability_smoke=reports/observability-smoke.json"
        ),
    }
    from reactor.release.readiness_evidence import readiness_failure_summary

    summary = readiness_failure_summary(report)
    assert (
        "tagRecommendation status=defer eligible=false "
        "recommendedVersionBump=none recommendedTagPattern=none minorEligible=false "
        "blockingReports=observability_smoke passedReports=hardening_suite "
        "nextAction='resolve blocked/skipped release readiness reports before tagging' "
        "remediationCommand='uv run reactor-observability-smoke "
        "--output reports/observability-smoke.json' "
        "readinessReportArg='--readiness-report "
        "observability_smoke=reports/observability-smoke.json'"
    ) in summary


@pytest.mark.parametrize(
    ("report_name", "file_name", "expected_command"),
    [
        (
            "smoke_run",
            "release-smoke-run.json",
            (
                "uv run reactor-release-smoke-run "
                "--plan reports/release/release-smoke-plan.local.json "
                "--preflight-file reports/release/release-smoke-preflight.local.json "
                "--env-file reports/release/release-smoke-preflight.local.env "
                "--preflight-only "
                "--readiness-output reports/release-readiness.json"
            ),
        ),
        (
            "release_evidence",
            "release-evidence.json",
            (
                "uv run reactor-release-smoke-run "
                "--plan reports/release/release-smoke-plan.local.json "
                "--report-file reports/release-smoke-run.json "
                "--verified-at <ISO-8601> "
                "--evidence-output reports/release-evidence.json"
            ),
        ),
    ],
)
def test_release_readiness_report_shows_remediation_when_report_file_is_missing(
    tmp_path: Path,
    report_name: str,
    file_name: str,
    expected_command: str,
) -> None:
    missing_report = tmp_path / file_name

    report = build_release_readiness_report(
        [(report_name, missing_report)],
        required_reports=(report_name,),
    )

    assert report["ok"] is False
    assert report["status"] == "failed"
    assert report["missingReports"] == []
    items = cast(list[dict[str, object]], report["items"])
    assert items == [
        {
            "name": report_name,
            "ok": False,
            "status": "failed",
            "scope": "",
            "artifact": str(missing_report),
            "owner": "",
            "mode": "",
            "failure": "readiness report file missing",
            "remediationCommand": expected_command,
            "readinessReportArg": f"--readiness-report {report_name}={missing_report}",
        }
    ]
    recommendation = cast(dict[str, object], report["tagRecommendation"])
    assert recommendation["blockingReports"] == [report_name]
    assert recommendation["remediationCommand"] == expected_command
    assert (
        recommendation["readinessReportArg"] == f"--readiness-report {report_name}={missing_report}"
    )


