def test_release_readiness_fails_minor_tag_recommendation_without_release_command(
    tmp_path: Path,
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    import reactor.release.readiness_evidence as readiness_module

    evidence = valid_rag_candidate_langsmith_eval_sync_evidence()
    evidence["feedbackPromotion"] = valid_rag_candidate_feedback_promotion()
    evidence["ragIngestionLifecycle"] = valid_rag_ingestion_lifecycle()
    langsmith = write_report(
        tmp_path / "langsmith-eval-sync.json",
        {
            "ok": True,
            "status": "passed",
            "scope": "langsmith_eval_dataset_sync",
            "evidence": evidence,
        },
    )
    real_tag_recommendation = readiness_module.tag_recommendation

    def tag_recommendation_without_release_command(
        *args: Any,
        **kwargs: Any,
    ) -> dict[str, object]:
        recommendation = real_tag_recommendation(*args, **kwargs)
        recommendation.pop("releaseReadinessCommand", None)
        return recommendation

    monkeypatch.setattr(
        readiness_module,
        "tag_recommendation",
        tag_recommendation_without_release_command,
    )

    report = build_release_readiness_report(
        [("langsmith_eval_sync", langsmith)],
        required_reports=("langsmith_eval_sync",),
    )

    assert report["ok"] is False
    assert report["status"] == "failed"
    assert report["failure"] == "tag recommendation contract missing"
    recommendation = cast(dict[str, object], report["tagRecommendation"])
    assert recommendation["recommendedVersionBump"] == "minor"
    assert recommendation["minorEligible"] is True
    assert "releaseReadinessCommand" not in recommendation


