def test_release_readiness_derives_minor_boundary_across_hardening_and_langsmith(
    tmp_path: Path,
) -> None:
    hardening = write_report(
        tmp_path / "hardening-suite.json",
        {
            "ok": True,
            "status": "passed",
            "scope": "agent_release_gate",
            "evidence": valid_hardening_suite_evidence(),
        },
    )
    langsmith_evidence = valid_rag_candidate_langsmith_eval_sync_evidence()
    langsmith_evidence["feedbackPromotion"] = valid_rag_candidate_feedback_promotion()
    langsmith_evidence["productCapabilityBoundary"] = {
        "minorEligible": False,
        "capability": "rag_ingest_to_feedback_eval_langsmith_readiness",
        "evidence": [
            "rag_ingestion_candidate_feedback_queue",
            "langsmith_trace_grading",
            "release_readiness_command",
        ],
        "missingEvidence": ["rag_ingestion_lifecycle"],
    }
    langsmith = write_report(
        tmp_path / "langsmith-eval-sync.json",
        {
            "ok": True,
            "status": "passed",
            "scope": "langsmith_eval_dataset_sync",
            "evidence": langsmith_evidence,
        },
    )

    report = build_release_readiness_report(
        [("hardening_suite", hardening), ("langsmith_eval_sync", langsmith)],
        required_reports=("hardening_suite", "langsmith_eval_sync"),
    )

    assert report["ok"] is True
    items = {item["name"]: item for item in cast(list[dict[str, object]], report["items"])}
    assert items["langsmith_eval_sync"]["productCapabilityBoundary"] == {
        "minorEligible": True,
        "capability": "rag_ingest_to_feedback_eval_langsmith_readiness",
        "evidence": [
            "rag_ingestion_lifecycle",
            "rag_ingestion_candidate_feedback_queue",
            "eval_promotion_apply_coverage",
            "feedback_promotion.reviewed_feedback",
            "feedback_promotion_review",
            "context_manifest_diagnostics_citation_workflow",
            "langsmith_trace_grading",
            "release_readiness_command",
        ],
    }
    assert report["tagRecommendation"] == {
        "status": "eligible_with_warnings",
        "reason": "required release readiness reports passed with warnings",
        "eligible": True,
        "recommendedVersionBump": "minor",
        "recommendedTagPattern": "v1.2.0",
        "minorEligible": True,
        "minorBoundaryReports": ["langsmith_eval_sync"],
        "releaseReadinessCommand": langsmith_evidence["readinessCommand"],
        "policy": "version tags are only for release-worthy batches or deployment candidates",
        "passedReports": ["hardening_suite", "langsmith_eval_sync"],
        "nextAction": (
            "review release readiness warnings, then verify clean worktree and choose the "
            "next minor version tag"
        ),
        "warningReports": ["hardening_suite"],
        "warningReviewRequired": True,
    }


