def test_release_readiness_marks_hardening_lifecycle_resolved_for_langsmith_dry_run(
    tmp_path: Path,
) -> None:
    hardening = write_report(
        tmp_path / "hardening-suite.json",
        {
            "ok": True,
            "status": "passed",
            "scope": "agent_release_gate",
            "evidence": valid_hardening_suite_evidence(),
        },
    )
    langsmith_evidence = valid_rag_candidate_langsmith_eval_sync_evidence()
    langsmith_evidence["productCapabilityBoundary"] = {
        "minorEligible": False,
        "capability": "rag_ingest_to_feedback_eval_langsmith_readiness",
        "evidence": [
            "rag_ingestion_candidate_feedback_queue",
            "langsmith_trace_grading",
            "release_readiness_command",
        ],
        "missingEvidence": ["rag_ingestion_lifecycle"],
    }
    langsmith_evidence["nextActions"] = [
        {
            "id": "generate-hardening-suite",
            "label": "Generate the hardening suite report required for minor boundary review",
            "command": "uv run reactor-hardening-suite --report-file reports/hardening-suite.json",
        },
        {
            "id": "sync-langsmith",
            "label": "Run the LangSmith eval sync without dry-run",
            "command": cast(str, langsmith_evidence["liveSyncCommand"]),
            "requiredReviewNote": "Reviewed RAG candidate feedback before release.",
            "remediationCommand": (
                cast(str, langsmith_evidence["liveSyncCommand"])
                + " --preflight-only --output table"
            ),
            "requiredEnvAnyOf": [["LANGSMITH_API_KEY", "REACTOR_OBSERVABILITY_LANGSMITH_API_KEY"]],
            "recommendedEnv": ["LANGSMITH_ENDPOINT"],
        },
    ]
    langsmith = write_report(
        tmp_path / "langsmith-eval-sync-dry-run.json",
        {
            "ok": False,
            "status": "skipped",
            "scope": "langsmith_eval_dataset_sync",
            "evidence": langsmith_evidence,
            "releaseGate": {
                "status": "blocked",
                "blocksReleaseReadiness": True,
                "reason": "dry_run_only",
                "requiredReport": "langsmith_eval_sync",
                "remediation": [
                    "run_reactor_langsmith_eval_sync_without_dry_run",
                    "include_passed_langsmith_eval_sync_report_in_release_readiness",
                ],
            },
        },
    )

    report = build_release_readiness_report(
        [("hardening_suite", hardening), ("langsmith_eval_sync", langsmith)],
        required_reports=("hardening_suite", "langsmith_eval_sync"),
    )

    assert report["ok"] is False
    assert report["status"] == "blocked"
    items = {item["name"]: item for item in cast(list[dict[str, object]], report["items"])}
    assert items["langsmith_eval_sync"]["status"] == "skipped"
    assert items["langsmith_eval_sync"]["productBoundaryResolvedEvidence"] == [
        "rag_ingestion_lifecycle"
    ]
    assert items["langsmith_eval_sync"]["productBoundaryResolvedByReports"] == {
        "rag_ingestion_lifecycle": "hardening_suite"
    }
    next_action_ids = [
        action["id"]
        for action in cast(list[dict[str, object]], items["langsmith_eval_sync"]["nextActions"])
    ]
    assert "generate-hardening-suite" not in next_action_ids
    assert "sync-langsmith" in next_action_ids
    assert report["tagRecommendation"] == {
        "status": "defer",
        "reason": "release readiness is blocked",
        "eligible": False,
        "recommendedVersionBump": "none",
        "recommendedTagPattern": "none",
        "minorEligible": False,
        "policy": "version tags are only for release-worthy batches or deployment candidates",
        "blockingReports": ["langsmith_eval_sync"],
        "passedReports": ["hardening_suite"],
        "minorBoundaryResolvedEvidence": ["rag_ingestion_lifecycle"],
        "minorBoundaryResolvedByReports": {
            "rag_ingestion_lifecycle": "hardening_suite",
        },
        "nextAction": "run nextAction.sync-langsmith before tagging",
        "nextActionId": "sync-langsmith",
        "nextActionCommand": langsmith_evidence["liveSyncCommand"],
        "readyNextActionIds": ["sync-langsmith"],
        "nextActionStates": {"sync-langsmith": "ready"},
        "requiredReviewNote": "Reviewed RAG candidate feedback before release.",
        "remediationCommand": (
            cast(str, langsmith_evidence["liveSyncCommand"]) + " --preflight-only --output table"
        ),
        "requiredEnvAnyOf": [["LANGSMITH_API_KEY", "REACTOR_OBSERVABILITY_LANGSMITH_API_KEY"]],
        "recommendedEnv": ["LANGSMITH_ENDPOINT"],
        "readinessReportArg": (
            "--readiness-report hardening_suite=reports/hardening-suite.json "
            f"--readiness-report langsmith_eval_sync={langsmith}"
        ),
        "requiredReadinessReports": ["hardening_suite", "langsmith_eval_sync"],
        "readinessReports": {
            "hardening_suite": "reports/hardening-suite.json",
            "langsmith_eval_sync": str(langsmith),
        },
    }


