def test_release_readiness_report_summarizes_memory_dependency_warnings(
    tmp_path: Path,
) -> None:
    hardening = write_report(
        tmp_path / "hardening-suite.json",
        {
            "ok": True,
            "status": "passed",
            "scope": "agent_release_gate",
            "evidence": valid_hardening_suite_evidence(),
        },
    )

    report = build_release_readiness_report([("hardening_suite", hardening)])

    assert report["ok"] is True
    assert report["warnings"] == [
        {
            "name": "hardening_suite",
            "source": "memoryMaintenanceLifecycle.dependencyWarnings",
            "status": "review_required",
            "findings": [
                {
                    "package": "trustcall",
                    "module": "trustcall._base",
                    "deprecatedImport": "langgraph.constants.Send",
                    "replacement": "langgraph.types.Send",
                    "severity": "warning",
                }
            ],
            "remediation": "review LangMem/trustcall/LangGraph dependency update",
            "reviewCommand": "uv pip show langmem trustcall langgraph",
            "remediationCommand": (
                "monitor upstream trustcall/langmem compatibility; keep "
                "dependency warning visible until "
                "trustcall stops importing langgraph.constants.Send or "
                "Reactor replaces the dependency path"
            ),
        }
    ]
    tag_recommendation = cast(dict[str, object], report["tagRecommendation"])
    assert tag_recommendation["status"] == "eligible_with_warnings"
    assert tag_recommendation["eligible"] is True
    assert tag_recommendation["warningReports"] == ["hardening_suite"]
    assert tag_recommendation["warningReviewRequired"] is True
    assert tag_recommendation["nextAction"] == (
        "review release readiness warnings, then verify clean worktree and choose the "
        "next patch version tag"
    )


