def test_release_readiness_preserves_top_level_api_smoke_next_actions() -> None:
    report = build_release_readiness_report_from_payloads(
        [
            (
                "dress_api_smoke",
                {
                    "ok": False,
                    "status": "skipped",
                    "scope": "dress_rehearsal",
                    "error": "missing required API smoke environment",
                    "checks": {
                        "required_env": {
                            "status": "failed",
                            "variables": ["REACTOR_API_BASE_URL", "REACTOR_API_KEY"],
                            "missing": ["REACTOR_API_BASE_URL", "REACTOR_API_KEY"],
                        }
                    },
                    "nextActions": [
                        {
                            "id": "configure_api_smoke_env",
                            "label": "Configure API smoke environment",
                            "command": (
                                "REACTOR_API_BASE_URL=<api-url> "
                                "REACTOR_API_KEY=<api-key> "
                                "uv run reactor-dress-api-smoke --output "
                                "reports/full-backup-db-api-dress-rehearsal.json"
                            ),
                            "requiredEnv": ["REACTOR_API_BASE_URL", "REACTOR_API_KEY"],
                            "missingEnv": ["REACTOR_API_BASE_URL", "REACTOR_API_KEY"],
                            "reportFile": "reports/full-backup-db-api-dress-rehearsal.json",
                        }
                    ],
                },
                "reports/full-backup-db-api-dress-rehearsal.json",
            )
        ],
        required_reports=["dress_api_smoke"],
    )

    items = {item["name"]: item for item in cast(list[dict[str, object]], report["items"])}
    assert items["dress_api_smoke"]["nextActions"] == [
        {
            "id": "configure_api_smoke_env",
            "label": "Configure API smoke environment",
            "command": (
                "REACTOR_API_BASE_URL=<api-url> REACTOR_API_KEY=<api-key> "
                "uv run reactor-dress-api-smoke --output "
                "reports/full-backup-db-api-dress-rehearsal.json"
            ),
            "requiredEnv": ["REACTOR_API_BASE_URL", "REACTOR_API_KEY"],
            "missingEnv": ["REACTOR_API_BASE_URL", "REACTOR_API_KEY"],
            "reportFile": "reports/full-backup-db-api-dress-rehearsal.json",
        }
    ]
    tag_recommendation = cast(dict[str, object], report["tagRecommendation"])
    assert tag_recommendation["nextActionId"] == "configure_api_smoke_env"
    assert (
        tag_recommendation["nextActionCommand"]
        == "REACTOR_API_BASE_URL=<api-url> REACTOR_API_KEY=<api-key> "
        "uv run reactor-dress-api-smoke --output "
        "reports/full-backup-db-api-dress-rehearsal.json"
    )


