def test_release_readiness_evidence_cli_rejects_duplicate_report_names(
    tmp_path: Path,
) -> None:
    first = tmp_path / "langsmith-first.json"
    second = tmp_path / "langsmith-second.json"
    for path in (first, second):
        path.write_text(
            json.dumps({"ok": True, "status": "passed", "scope": "langsmith_eval_dataset_sync"}),
            encoding="utf-8",
        )

    with pytest.raises(ValueError, match="duplicate --report name: langsmith_eval_sync"):
        main(
            [
                "--report",
                f"langsmith_eval_sync={first}",
                "--report",
                f"langsmith_eval_sync={second}",
                "--output",
                str(tmp_path / "release-readiness.json"),
            ]
        )


