def test_readiness_summary_includes_minor_boundary_remediation() -> None:
    from reactor.release.readiness_evidence import readiness_failure_summary

    summary = readiness_failure_summary(
        {
            "status": "passed",
            "tagRecommendation": {
                "status": "eligible",
                "eligible": True,
                "recommendedVersionBump": "patch",
                "recommendedTagPattern": "v1.0.x",
                "minorEligible": False,
                "minorBlockedReason": "no passed product capability boundary evidence",
                "minorBlockedReports": ["langsmith_eval_sync"],
                "minorBoundaryMissingEvidence": [
                    "eval_promotion_apply_coverage",
                    "feedback_promotion.reviewed_feedback",
                ],
                "minorBoundaryResolvedEvidence": ["rag_ingestion_lifecycle"],
                "minorBoundaryResolvedByReports": {
                    "rag_ingestion_lifecycle": "hardening_suite",
                },
                "minorBoundaryRemediationCommand": (
                    "reactor-runs promote-eval run_c1 --case-id case_c1 "
                    "--apply-suite-file evals/regression/rag-ingestion-candidate.json "
                    "--apply-dry-run"
                ),
                "passedReports": ["langsmith_eval_sync"],
                "nextAction": "verify clean worktree and choose the next patch version tag",
            },
            "items": [],
        }
    )

    assert "minorBlockedReports=langsmith_eval_sync" in summary
    assert (
        "minorBoundaryMissing=eval_promotion_apply_coverage,feedback_promotion.reviewed_feedback"
    ) in summary
    assert "minorBoundaryResolved=rag_ingestion_lifecycle" in summary
    assert "minorBoundaryResolvedBy.rag_ingestion_lifecycle=hardening_suite" in summary
    assert (
        "minorBoundaryRemediationCommand='reactor-runs promote-eval run_c1 "
        "--case-id case_c1 "
        "--apply-suite-file evals/regression/rag-ingestion-candidate.json'"
    ) in summary
    assert "--apply-dry-run" not in summary


