def test_readiness_failure_summary_includes_release_gate_remediation_command() -> None:
    from reactor.release.readiness_evidence import readiness_failure_summary

    summary = readiness_failure_summary(
        {
            "status": "failed",
            "items": [
                {
                    "name": "langsmith_eval_sync",
                    "status": "failed",
                    "failure": "feedback_review_queue_source_missing",
                    "releaseGate": {
                        "status": "blocked",
                        "reason": "feedback_review_queue_source_missing",
                        "remediationCommand": (
                            "reactor-admin feedback --rating thumbs_down "
                            "--tag collection:rag-ingestion-candidate --output table"
                        ),
                        "remediation": ["resubmit_feedback_with_source_metadata"],
                    },
                }
            ],
        }
    )

    assert (
        "releaseGate=blocked "
        "gateReason=feedback_review_queue_source_missing "
        "releaseGateRemediationCommand='reactor-admin feedback --rating thumbs_down "
        "--tag collection:rag-ingestion-candidate --output table' "
        "releaseNext=resubmit_feedback_with_source_metadata"
    ) in summary


