def test_release_readiness_tag_recommendation_includes_preflight_env_blockers() -> None:
    from reactor.release.readiness_evidence import build_release_readiness_report_from_items

    report = build_release_readiness_report_from_items(
        [
            {
                "name": "preflight",
                "status": "blocked",
                "failure": "release smoke preflight blocked by missing environment",
                "preflightMissingEnv": ["OPENAI_API_KEY", "REACTOR_A2A_API_KEY"],
                "preflightMissingAnyOf": [
                    "LANGSMITH_API_KEY|REACTOR_OBSERVABILITY_LANGSMITH_API_KEY"
                ],
                "remediationCommand": (
                    "uv run reactor-release-smoke-run --plan reports/release-smoke-plan.json "
                    "--preflight-only"
                ),
            }
        ],
        required_reports=("preflight",),
    )

    recommendation = cast(dict[str, object], report["tagRecommendation"])
    assert recommendation["status"] == "defer"
    assert recommendation["blockingReports"] == ["preflight"]
    assert recommendation["rootBlockingReports"] == ["preflight"]
    assert recommendation["blockingNextActions"] == [
        {
            "report": "preflight",
            "nextAction": "set release smoke preflight environment before tagging",
            "missingEnv": ["OPENAI_API_KEY", "REACTOR_A2A_API_KEY"],
            "missingEnvAnyOf": ["LANGSMITH_API_KEY|REACTOR_OBSERVABILITY_LANGSMITH_API_KEY"],
            "requiredEnvAnyOf": [["LANGSMITH_API_KEY", "REACTOR_OBSERVABILITY_LANGSMITH_API_KEY"]],
            "readyNextActionIds": ["set-release-smoke-preflight-env"],
            "nextActionStates": {"set-release-smoke-preflight-env": "ready"},
            "remediationCommand": (
                "uv run reactor-release-smoke-run --plan reports/release-smoke-plan.json "
                "--preflight-only"
            ),
        }
    ]
    assert report["readyNextActionIds"] == ["set-release-smoke-preflight-env"]
    assert report["nextActionStates"] == {"set-release-smoke-preflight-env": "ready"}
    assert recommendation["missingEnv"] == ["OPENAI_API_KEY", "REACTOR_A2A_API_KEY"]
    assert recommendation["missingEnvAnyOf"] == [
        "LANGSMITH_API_KEY|REACTOR_OBSERVABILITY_LANGSMITH_API_KEY"
    ]
    assert recommendation["remediationCommand"] == (
        "uv run reactor-release-smoke-run --plan reports/release-smoke-plan.json --preflight-only"
    )
    summary = readiness_failure_summary(report)
    assert "missingEnv=OPENAI_API_KEY,REACTOR_A2A_API_KEY" in summary
    assert ("missingEnvAnyOf=LANGSMITH_API_KEY|REACTOR_OBSERVABILITY_LANGSMITH_API_KEY") in summary


def test_release_readiness_preserves_ready_local_contract_actions_for_blocked_preflight() -> None:
    report = build_release_readiness_report_from_payloads(
        [
            (
                "preflight",
                {
                    "ok": False,
                    "status": "blocked",
                    "scope": "release_smoke_preflight",
                    "summary": {"total": 2, "ready": 1, "blocked": 1, "optional_missing": 0},
                    "steps": [
                        {
                            "code": "live_provider_runtime_smoke",
                            "status": "blocked",
                            "evidence_scope": "live",
                            "missing": ["OPENAI_API_KEY"],
                        },
                        {
                            "code": "live_provider_runtime_local_contract",
                            "status": "ready",
                            "evidence_scope": "local_contract",
                            "evidence_uri": "reports/local-provider-runtime-contract.json",
                            "command": [
                                "uv",
                                "run",
                                "pytest",
                                "tests/unit/test_langchain_agent.py",
                                "tests/unit/test_run_service.py",
                            ],
                        },
                    ],
                    "preflightMissingEnv": ["OPENAI_API_KEY"],
                    "remediationCommand": (
                        "uv run reactor-release-smoke-run --preflight-only "
                        "--env-file reports/release/release-smoke-preflight.local.env"
                    ),
                },
                "reports/release/release-smoke-preflight.local.json",
            )
        ],
        required_reports=("preflight",),
    )

    item = cast(list[dict[str, object]], report["items"])[0]
    expected_action = {
        "id": "run-live-provider-runtime-local-contract",
        "code": "live_provider_runtime_local_contract",
        "command": (
            "uv run pytest tests/unit/test_langchain_agent.py tests/unit/test_run_service.py"
        ),
        "evidenceUri": "reports/local-provider-runtime-contract.json",
    }
    assert item["readyLocalContractActions"] == [expected_action]
    recommendation = cast(dict[str, object], report["tagRecommendation"])
    blocking_action = cast(list[dict[str, object]], recommendation["blockingNextActions"])[0]
    assert blocking_action["readyLocalContractActions"] == [expected_action]
    assert "run-live-provider-runtime-local-contract" in cast(
        list[str],
        report["readyNextActionIds"],
    )
    assert (
        cast(dict[str, str], report["nextActionStates"])["run-live-provider-runtime-local-contract"]
        == "ready"
    )
    summary = readiness_failure_summary(report)
    assert (
        "blockingNextAction.preflight.readyLocalContractActions."
        "run-live-provider-runtime-local-contract="
        "'uv run pytest tests/unit/test_langchain_agent.py tests/unit/test_run_service.py'"
    ) in summary


