def test_release_readiness_preserves_unreadable_env_file_handoff() -> None:
    report = build_release_readiness_report_from_payloads(
        [
            (
                "langsmith_eval_sync",
                {
                    "ok": False,
                    "status": "blocked",
                    "scope": "langsmith_eval_dataset_sync",
                    "failure": "langsmith_env_file_unreadable",
                    "envFile": "reports/release/missing.env",
                    "releaseGateReason": "langsmith_env_file_unreadable",
                    "releaseGate": {
                        "status": "blocked",
                        "blocksReleaseReadiness": True,
                        "reason": "langsmith_env_file_unreadable",
                        "requiredReport": "langsmith_eval_sync",
                        "remediationCommand": "uv run reactor-langsmith-eval-sync --preflight-only",
                    },
                    "remediationCommand": "uv run reactor-langsmith-eval-sync --preflight-only",
                    "evidence": {
                        "artifact": "reports/langsmith-eval-sync.json",
                        "owner": "reactor.evals",
                        "mode": "langsmith_dataset_sync",
                        "envFile": "reports/release/missing.env",
                        "releaseGateReason": "langsmith_env_file_unreadable",
                        "remediationCommand": (
                            "uv run reactor-langsmith-eval-sync --preflight-only"
                        ),
                    },
                },
                "reports/langsmith-eval-sync.json",
            )
        ],
        required_reports=("langsmith_eval_sync",),
    )

    item = cast(list[dict[str, object]], report["items"])[0]
    assert item["envFile"] == "reports/release/missing.env"
    summary = cast(str, report["failureSummary"])
    assert "envFile='reports/release/missing.env'" in summary
    assert "gateReason=langsmith_env_file_unreadable" in summary


